select 
	msi_billing.techie, 
	msi_clients.company, 
	msi_billing.bill_hrs, 
	COUNT(msi_billing.bill_hrs)
from 
	msi_billing 
inner join 
	msi_clients 
on 
	msi_clients.id = msi_billing.client
where msi_billing.techie = 49 AND
	(msi_billing.date BETWEEN '2025-06-01' AND '2025-06-30') AND 
	msi_billing.type = 'Contract'
GROUP BY msi_billing.client, msi_billing.techie;

select * from msi_billing where techie = 49;

select * from msi_clients where id = 1;

select 
msi_contract.hours, msi_clients.company 
from msi_contract 
inner join msi_clients on msi_contract.client = msi_clients.id
where primarytech = 'thaakier' 
and terminating = 'no' and enddate  >= CURDATE() 
order by client asc;


